prompt --application/pages/page_00003
begin
wwv_flow_imp_page.create_page(
 p_id=>3
,p_name=>'Detalle Bar'
,p_alias=>'DETALLE-BAR'
,p_step_title=>'Detalle Bar'
,p_autocomplete_on_off=>'OFF'
,p_javascript_code=>wwv_flow_string.join(wwv_flow_t_varchar2(
'const API_BASE = ''https://parranderos-api-v0t3.onrender.com/bares''; // URL de su API en Render',
'const barId = parseInt(apex.item(''BAR_IDCARD'').getValue());',
'',
'function cargarComentarios() {',
' fetch(`${API_BASE}/${barId}/comentarios`)',
' .then(res => res.json())',
' .then(data => {',
' const container = document.getElementById(''comentarioscontainer'');',
' if (data.length === 0) {',
unistr(' container.innerHTML = ''<p>No hay comentarios a\00FAn. \00A1S\00E9 el primero!</p>'';'),
' return;',
' }',
' container.innerHTML = data.map(c => `',
' <div style="border:1px solid #ddd; border-radius:8px;',
'padding:12px; margin-bottom:10px;">',
unistr(' <strong>${c.autor || ''An\00F3nimo''}</strong>'),
' <span style="color:#888; font-size:0.85em; marginleft:10px;">',
' ${c.date ? new Date(c.date).toLocaleDateString(''esCO'') : ''''}',
' </span>',
' <p style="margin-top:6px;">${c.texto}</p>',
' </div>',
' `).join('''');',
' })',
' .catch(err => {',
' document.getElementById(''comentarios-container'').innerHTML =',
' ''<p style="color:red;">Error cargando comentarios.</p>'';',
' });',
'}',
'',
'',
'function enviarComentario() {',
' const texto = apex.item(''INFO_COMENTARIO'').getValue();',
' if (!texto.trim()) {',
unistr(' apex.message.showErrors([{ message: ''El comentario no puede estar vac\00EDo.'' }]);'),
' return;',
' }',
' fetch(`${API_BASE}/${barId}/comentarios`, {',
' method: ''POST'',',
' headers: { ''Content-Type'': ''application/json'' },',
' body: JSON.stringify({',
' bar_id: parseInt(barId),',
' texto: texto,',
unistr(' autor: apex.env.APP_USER // usuario de sesi\00F3n APEX'),
' })',
' })',
' .then(res => res.json())',
' .then(() => {',
' apex.item(''AUTOR'').setValue('''');',
' cargarComentarios(); // refresca la lista',
' })',
' .catch(() => {',
' apex.message.showErrors([{ message: ''Error enviando el comentario.'' }]);',
' });',
'}',
''))
,p_javascript_code_onload=>'cargarComentarios();'
,p_page_template_options=>'#DEFAULT#'
,p_protection_level=>'C'
,p_page_component_map=>'03'
,p_last_updated_by=>'REALES'
,p_last_upd_yyyymmddhh24miss=>'20260517032821'
);
