wwv_flow_imp_page.create_page_plug(
 p_id=>wwv_flow_imp.id(112251662318800567016)
,p_plug_name=>'Eventos'
,p_region_template_options=>'#DEFAULT#:t-Region--scrollBody'
,p_plug_template=>wwv_flow_imp.id(114336993781329071587)
,p_plug_display_sequence=>50
,p_include_in_reg_disp_sel_yn=>'Y'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
' <style>',
'  #ev-wrap { font-family: inherit; margin-top: 30px; }',
'',
'  #ev-wrap h3 {',
'    font-size: 1.2rem;',
'    font-weight: 600;',
'    border-bottom: 2px solid #ddd;',
'    padding-bottom: 8px;',
'    margin-bottom: 16px;',
'    color: #333;',
'  }',
'',
'  #ev-lista {',
'    display: grid;',
'    grid-template-columns: repeat(auto-fill, minmax(240px, 1fr));',
'    gap: 12px;',
'    margin-bottom: 20px;',
'  }',
'',
'  .ev-card {',
'    border: 1px solid #ddd;',
'    border-radius: 8px;',
'    padding: 14px;',
'    background: #fafafa;',
'  }',
'',
'  .ev-card strong { display: block; margin-bottom: 8px; font-size: 0.95rem; }',
'',
'  .ev-fila {',
'    display: flex;',
'    justify-content: space-between;',
'    font-size: 0.82rem;',
'    color: #555;',
'    padding: 3px 0;',
'    border-bottom: 1px solid #eee;',
'  }',
'',
'  .ev-fila:last-child { border-bottom: none; }',
'  .ev-fila span:last-child { color: #222; font-weight: 500; }',
'',
'  .ev-msg { color: #888; font-size: 0.9rem; padding: 20px 0; }',
'',
'  #ev-form-wrap {',
'    border: 1px solid #ddd;',
'    border-radius: 8px;',
'    padding: 20px;',
'    background: #fafafa;',
'    max-width: 480px;',
'  }',
'',
'  #ev-form-wrap h4 { margin: 0 0 16px; font-size: 1rem; font-weight: 600; }',
'',
'  .ev-group { margin-bottom: 14px; }',
'',
'  .ev-group label {',
'    display: block;',
'    font-size: 0.82rem;',
'    font-weight: 600;',
'    color: #555;',
'    margin-bottom: 4px;',
'  }',
'',
'  .ev-group input, .ev-group select {',
'    width: 100%;',
'    border: 1px solid #ccc;',
'    border-radius: 6px;',
'    padding: 8px 10px;',
'    font-size: 0.9rem;',
'    box-sizing: border-box;',
'    background: #fff;',
'  }',
'',
'  .ev-group input:focus, .ev-group select:focus {',
'    outline: none;',
'    border-color: #666;',
'  }',
'',
'  #ev-opcionales {',
'    background: #f0f0f0;',
'    border-radius: 6px;',
'    padding: 14px;',
'    margin-bottom: 14px;',
'  }',
'',
'  #ev-opcionales p { font-size: 0.8rem; color: #888; margin: 0; }',
'',
'  .ev-btn {',
'    background: #333;',
'    color: #fff;',
'    border: none;',
'    border-radius: 6px;',
'    padding: 9px 20px;',
'    font-size: 0.9rem;',
'    cursor: pointer;',
'  }',
'',
'  .ev-btn:hover { background: #555; }',
'',
'  #ev-feedback { font-size: 0.85rem; margin-top: 10px; color: green; display: none; }',
'  #ev-feedback.error { color: red; }',
'</style>',
'',
'<div id="ev-wrap">',
'  <h3>Eventos <span id="ev-count" style="font-weight:400;font-size:0.9rem;color:#888;"></span></h3>',
'  <div id="ev-lista"><p class="ev-msg">Cargando...</p></div>',
'',
'  <div id="ev-form-wrap">',
'    <h4>Registrar nuevo evento</h4>',
'',
'    <div class="ev-group">',
'      <label for="ev-nombre">Nombre *</label>',
'      <input type="text" id="ev-nombre" placeholder="Nombre del evento">',
'    </div>',
'',
'    <div class="ev-group">',
'      <label for="ev-tipo">Tipo de evento</label>',
'      <select id="ev-tipo" onchange="evTipo()">',
'        <option value="">Selecciona un tipo</option>',
'        <option value="concierto">Concierto</option>',
'        <option value="happyhour">Happy Hour</option>',
unistr('        <option value="fiesta">Fiesta tem\00E1tica</option>'),
'        <option value="trivia">Noche de trivia</option>',
'        <option value="otro">Otro</option>',
'      </select>',
'    </div>',
'',
'    <div id="ev-opcionales">',
'      <p>Selecciona un tipo para ver campos adicionales</p>',
'    </div>',
'',
'    <button class="ev-btn" onclick="evGuardar()">Guardar evento</button>',
'    <div id="ev-feedback"></div>',
'  </div>',
'</div>',
'',
'<script>',
'(function() {',
'  var API = "https://parranderos-api-v0t3.onrender.com";',
'',
'  var CAMPOS = {',
'    concierto: [',
'      { id:"ev-artista", label:"Artista",    type:"text",   key:"artista",     ph:"Ej: Trio Bogota" },',
'      { id:"ev-cover",   label:"Cover ($)",  type:"number", key:"cover",       ph:"Ej: 15000" },',
'      { id:"ev-cupos",   label:"Cupos",      type:"number", key:"cupos",       ph:"Ej: 80" }',
'    ],',
'    happyhour: [',
'      { id:"ev-desc",    label:"Descuento",  type:"text",   key:"descuento",   ph:"Ej: 2x1 en cervezas" },',
'      { id:"ev-hinicio", label:"Hora inicio",type:"time",   key:"hora_inicio", ph:"" },',
'      { id:"ev-hfin",    label:"Hora fin",   type:"time",   key:"hora_fin",    ph:"" }',
'    ],',
'    fiesta: [',
'      { id:"ev-tema",    label:"Tema",       type:"text",   key:"tema",        ph:"Ej: Anos 80" },',
'      { id:"ev-dj",      label:"DJ",         type:"text",   key:"dj",          ph:"Ej: DJ Rumba" }',
'    ],',
'    trivia: [',
'      { id:"ev-ttema",   label:"Tema",       type:"text",   key:"tema",        ph:"Ej: Cultura general" },',
'      { id:"ev-premio",  label:"Premio",     type:"text",   key:"premio",      ph:"Ej: Ronda gratis" }',
'    ],',
'    otro: [',
'      { id:"ev-desc2",   label:"Descripcion",type:"text",   key:"descripcion", ph:"Describe el evento" }',
'    ]',
'  };',
'',
'  function getBarId() {',
'    if (window.apex && apex.item) {',
'      var v = apex.item("BAR_IDCARD").getValue();',
'      if (v) return v;',
'    }',
'    var el = document.getElementById("BAR_IDCARD");',
'    return el ? el.value : null;',
'  }',
'',
'  function cargar() {',
'    var id = getBarId();',
'    if (!id) { document.getElementById("ev-lista").innerHTML = ''<p class="ev-msg">No se encontro el ID del bar.</p>''; return; }',
'    fetch(API + "/bares/" + id + "/eventos")',
'      .then(function(r) { return r.json(); })',
'      .then(function(data) {',
'        var lista = Array.isArray(data) ? data : (data.eventos || []);',
'        var count = document.getElementById("ev-count");',
'        count.textContent = "(" + lista.length + ")";',
'        var cont = document.getElementById("ev-lista");',
'        if (!lista.length) { cont.innerHTML = ''<p class="ev-msg">No hay eventos registrados aun.</p>''; return; }',
'        var SKIP = ["_id","bar_id","__v","nombre"];',
'        cont.innerHTML = lista.map(function(ev) {',
'          var filas = Object.keys(ev).filter(function(k){ return SKIP.indexOf(k)===-1; }).map(function(k){',
'            var v = ev[k];',
'            if (k==="fecha_creacion" && v) try { v = new Date(v).toLocaleDateString("es-CO"); } catch(e){}',
'            return ''<div class="ev-fila"><span>'' + k.replace(/_/g," ") + ''</span><span>'' + v + ''</span></div>'';',
'          }).join("");',
'          return ''<div class="ev-card"><strong>'' + (ev.nombre||"Sin nombre") + ''</strong>'' + filas + ''</div>'';',
'        }).join("");',
'      })',
'      .catch(function() { document.getElementById("ev-lista").innerHTML = ''<p class="ev-msg">Error cargando eventos.</p>''; });',
'  }',
'',
'  window.evTipo = function() {',
'    var tipo = document.getElementById("ev-tipo").value;',
'    var cont = document.getElementById("ev-opcionales");',
'    if (!tipo || !CAMPOS[tipo]) { cont.innerHTML = ''<p>Selecciona un tipo para ver campos adicionales</p>''; return; }',
'    cont.innerHTML = CAMPOS[tipo].map(function(c) {',
'      return ''<div class="ev-group"><label>'' + c.label + ''</label>'' +',
'             ''<input type="'' + c.type + ''" id="'' + c.id + ''" placeholder="'' + c.ph + ''"></div>'';',
'    }).join("");',
'  };',
'',
'  window.evGuardar = function() {',
'    var id     = getBarId();',
'    var nombre = document.getElementById("ev-nombre").value.trim();',
'    var tipo   = document.getElementById("ev-tipo").value;',
'    var fb     = document.getElementById("ev-feedback");',
'',
'    if (!nombre) { fb.className="error"; fb.style.display="block"; fb.textContent="El nombre es obligatorio."; return; }',
'',
'    var doc = { nombre: nombre };',
'    if (tipo && CAMPOS[tipo]) {',
'      CAMPOS[tipo].forEach(function(c) {',
'        var el = document.getElementById(c.id);',
'        if (el && el.value.trim()) doc[c.key] = c.type==="number" ? Number(el.value) : el.value.trim();',
'      });',
'    }',
'',
'    fetch(API + "/bares/" + id + "/eventos", {',
'      method: "POST",',
'      headers: { "Content-Type": "application/json" },',
'      body: JSON.stringify(doc)',
'    })',
'    .then(function(r) { if (!r.ok) throw new Error("Error " + r.status); return r.json(); })',
'    .then(function() {',
'      fb.className=""; fb.style.display="block"; fb.textContent="Evento guardado correctamente.";',
'      document.getElementById("ev-nombre").value = "";',
'      document.getElementById("ev-tipo").value = "";',
'      document.getElementById("ev-opcionales").innerHTML = ''<p>Selecciona un tipo para ver campos adicionales</p>'';',
'      cargar();',
'    })',
'    .catch(function(e) { fb.className="error"; fb.style.display="block"; fb.textContent="Error: " + e.message; });',
'  };',
'',
'  if (window.apex) apex.jQuery(document).ready(cargar);',
'  else document.addEventListener("DOMContentLoaded", cargar);',
'})();',
'</script>'))
,p_plug_query_options=>'DERIVED_REPORT_COLUMNS'
,p_attribute_01=>'N'
,p_attribute_02=>'HTML'
);
